  ('dietitian-moex-10658', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關懷孕期飲食原則之敘述，何者不適當？ 懷孕初期若有噁心、嘔吐等現象，可採用高醣類飲食 懷孕期間要避免菸、酒、咖啡及刺激性食物 宜多補充維生素B，以防止胎兒神經系統發育的缺陷 6 宜多攝取膳食纖維質及水分，以預防便秘', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
